async fn process_batch(items: Vec<Item>) -> Result<(), Box<dyn std::error::Error>> {
    let results = Arc::new(Mutex::new(Vec::new()));

    for item in &items {
        let results = results.clone();
        let computed = heavy_computation(item);  // blocking CPU work in async!
        results.lock().unwrap().push(computed);  // unwrap in production!
    }

    let guard = results.lock().unwrap();
    // Do something with guard
    some_async_operation().await;  // holding MutexGuard across .await!
    println!("Processed {} items", guard.len());  // println in async code

    Ok(())
}

