Review this Rust code for performance issues and suggest improvements:

```rust
use std::collections::{HashMap, LinkedList};

fn process_ids(ids: &[u64]) -> Vec<String> {
    let mut results = Vec::new();
    for id in ids {
        results.push(format!("id-{}", id));
    }
    results
}

fn build_index(entries: &[(String, u64)]) -> HashMap<String, u64> {
    let mut map = HashMap::new();
    for (key, val) in entries {
        map.insert(key.clone(), *val);
    }
    map
}

struct EventQueue {
    events: LinkedList<Event>,
}

impl EventQueue {
    fn push(&mut self, event: Event) {
        self.events.push_back(event);
    }
    fn pop(&mut self) -> Option<Event> {
        self.events.pop_front()
    }
}

trait Processor {
    fn process(&self, data: &[u8]) -> Vec<u8>;
}

// Hot path — called millions of times
fn run_pipeline(processors: &[Box<dyn Processor>], data: &[u8]) -> Vec<u8> {
    let mut result = data.to_vec();
    for p in processors {
        result = p.process(&result);
    }
    result
}

// Cargo.toml
// [profile.release]
// opt-level = 3
```

The `process_ids` function is called with slices of 10,000+ elements. The `build_index` function processes datasets of 100k+ entries. The `run_pipeline` is the hot inner loop. The `EventQueue` handles a FIFO queue of events.

